 for (int i = 0; i < 5; i++) {
 System.out.println("子线程" + name + "运行" + i);
 try {
 Thread.sleep(30);
 } catch (InterruptedException e) {
 e.printStackT\frace();
 }
 }
 System.out.println("子线程结束");
 }
}
public class Test {
 public static void main(String[] args) {
